function solve(nums) {
    const n = nums.length;
    let count = 0;

    // Iterate over all possible starting indices i
    for (let i = 0; i < n; i++) {
        // current_or stores the bitwise OR of the subarray nums[i...j]
        let current_or = 0;

        // seen_elements is a set to store all unique elements in the current subarray nums[i...j]
        const seen_elements = new Set();

        // Iterate over all possible ending indices j, starting from i
        for (let j = i; j < n; j++) {
            const num_j = nums[j];

            // Update the bitwise OR for the subarray nums[i...j]
            current_or |= num_j;

            // Add the current element to the set of seen elements
            seen_elements.add(num_j);

            // Check the condition for a "good" subarray:
            // The bitwise OR of the subarray must equal at least one element present in the subarray.
            // Since the bitwise OR of a set of numbers must be greater than or equal to any individual element,
            // the condition simplifies to: is current_or present in seen_elements?
            // Wait, the problem states: "the bitwise OR equals *at least one* element that appears in the subarray".

            let is_good = false;
            for (const element of seen_elements) {
                if (current_or === element) {
                    is_good = true;
                    break;
                }
            }

            if (is_good) {
                count++;
            }
        }
    }

    return count;
}
