function solve(nums) {
    const n = nums.length;
    let goodSubarrayCount = 0;

    // Iterate over all possible starting indices i
    for (let i = 0; i < n; i++) {
        let currentOr = 0;
        // Iterate over all possible ending indices j (j >= i)
        for (let j = i; j < n; j++) {
            // Update the bitwise OR for the subarray nums[i...j]
            currentOr |= nums[j];

            // Check the condition for a "good" subarray:
            // The bitwise OR must equal at least one element in the subarray.
            let isGood = false;

            // We need to check if currentOr is equal to any element in nums[i...j].
            // Since currentOr is the OR of all elements, if currentOr equals any element 
            // nums[k] where i <= k <= j, it means that for every bit set in currentOr, 
            // that bit must have been set in nums[k].
            // More strongly, if currentOr == nums[k] for some k in [i, j], 
            // then all bits set in currentOr must have come from nums[k].
            // Since currentOr = OR(nums[i]...nums[j]), and nums[k] is one of them, 
            // the condition is equivalent to checking if currentOr is present in nums[i...j].

            for (let k = i; k <= j; k++) {
                if (currentOr === nums[k]) {
                    isGood = true;
                    break;
                }
            }

            if (isGood) {
                goodSubarrayCount++;
            }
        }
    }

    return goodSubarrayCount;
}
